css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: 'Georgia', 'Times New Roman', serif; background: #fafaf9; color: #1c1917; line-height: 1.7; }
header { border-bottom: 1px solid #e7e5e4; position: sticky; top: 0; background: rgba(250,250,249,0.9); backdrop-filter: blur(12px); z-index: 100; }
nav { display: flex; align-items: center; justify-content: space-between; max-width: 860px; margin: 0 auto; padding: 0 24px; height: 64px; }
.brand { font-size: 22px; font-weight: 700; color: #1c1917; font-style: italic; }
.nav-links { display: flex; gap: 28px; } .nav-links a { color: #78716c; text-decoration: none; font-family: sans-serif; font-size: 15px; transition: color 0.2s; } .nav-links a:hover { color: #1c1917; }
main { max-width: 860px; margin: 0 auto; padding: 0 24px; }
.hero-post { padding: 64px 0 48px; border-bottom: 1px solid #e7e5e4; }
.post-meta { display: flex; gap: 16px; align-items: center; margin-bottom: 20px; }
.category { background: #eef2ff; color: #4338ca; padding: 4px 12px; border-radius: 20px; font-size: 13px; font-weight: 600; font-family: sans-serif; }
.date { color: #78716c; font-size: 14px; font-family: sans-serif; }
.hero-post h1 { font-size: 48px; line-height: 1.15; font-weight: 700; margin-bottom: 20px; letter-spacing: -1px; }
.excerpt { font-size: 19px; color: #44403c; line-height: 1.75; margin-bottom: 28px; max-width: 680px; }
.post-footer { display: flex; justify-content: space-between; align-items: center; }
.author { display: flex; gap: 12px; align-items: center; }
.avatar { width: 40px; height: 40px; border-radius: 50%; background: linear-gradient(135deg, #4338ca, #6366f1); display: flex; align-items: center; justify-content: center; color: white; font-size: 13px; font-weight: 700; font-family: sans-serif; }
.author strong { display: block; font-size: 15px; font-family: sans-serif; } .author small { color: #78716c; font-size: 13px; font-family: sans-serif; }
.read-more { color: #4338ca; text-decoration: none; font-family: sans-serif; font-weight: 600; font-size: 15px; }
.posts-grid { padding: 48px 0; border-bottom: 1px solid #e7e5e4; }
.posts-grid h2 { font-size: 28px; font-weight: 700; margin-bottom: 32px; }
.grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; }
.post-card { padding: 28px; border: 1px solid #e7e5e4; border-radius: 16px; transition: all 0.2s; cursor: pointer; } .post-card:hover { border-color: #c7d2fe; box-shadow: 0 4px 20px rgba(0,0,0,0.06); transform: translateY(-2px); }
.post-tag { display: inline-block; color: #4338ca; font-size: 12px; font-weight: 700; font-family: sans-serif; letter-spacing: 1px; margin-bottom: 12px; }
.post-card h3 { font-size: 20px; font-weight: 700; margin-bottom: 10px; line-height: 1.35; } .post-card p { color: #78716c; font-size: 15px; margin-bottom: 20px; line-height: 1.6; font-family: sans-serif; }
.card-footer { display: flex; justify-content: space-between; font-size: 13px; color: #a8a29e; font-family: sans-serif; }
.newsletter { padding: 48px 0 64px; text-align: center; }
.newsletter h2 { font-size: 32px; font-weight: 700; margin-bottom: 12px; } .newsletter p { color: #78716c; font-size: 17px; margin-bottom: 24px; font-family: sans-serif; }
.newsletter-form { display: flex; gap: 12px; max-width: 440px; margin: 0 auto; }
.newsletter-form input { flex: 1; height: 48px; border-radius: 10px; border: 1px solid #e7e5e4; padding: 0 16px; font-size: 15px; font-family: sans-serif; outline: none; transition: border-color 0.2s; } input:focus { border-color: #6366f1; }
.newsletter-form button { height: 48px; padding: 0 24px; border-radius: 10px; border: none; background: #4338ca; color: white; font-weight: 700; font-family: sans-serif; cursor: pointer; }
